import{_ as i,o as e,c as l,ag as d}from"./chunks/framework.DXGyWiRo.js";const r="/images/lekt5701.jpg",c=JSON.parse('{"title":"Lektion 57","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion57.md","filePath":"lektionen/lektion57.md"}'),n={name:"lektionen/lektion57.md"};function s(a,t,o,u,h,p){return e(),l("div",null,[...t[0]||(t[0]=[d('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-57" tabindex="-1">Lektion 57 <a class="header-anchor" href="#lektion-57" aria-label="Permalink to &quot;Lektion 57&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>57.1. Aorist 4: s-Aorist</li><li>57.2. Übung</li></ul><h2 id="_57-1-aorist-4-s-aorist" tabindex="-1">57.1. Aorist 4: s-Aorist <a class="header-anchor" href="#_57-1-aorist-4-s-aorist" aria-label="Permalink to &quot;57.1. Aorist 4: s-Aorist&quot;">​</a></h2><p>| Der s-Aorist wird zu den meisten अनिट्-Wurzeln gebildet, sofern sie nicht ausschließlich eine andere Aoristform haben. Fakultative अनिट्-Wurzeln können im allgemeinen wahlweise diesen oder den iṣ-Aorist bilden. Auch अनिट्-Wurzeln, die das परस्मैपद nach der 1.,2. oder 6. Form des Aorist bilden, bilden das आत्मनेपद nach dem s-Aorist.</p><p>| | --- | | Bildung:</p><p>Augment + Wurzel + s + athematische Sekundärendung</p><p>|</p><p>Tabelle der Endungen mit Stammbildungssuffix</p><table><tbody><tr><td></td><th colspan="2">परस्मैपदम्</th><th colspan="2">आत्मनेपदम्</th></tr><tr><td></td><th>एकवचनम्</th><th>बहुवचनम्</th><th>एकवचनम्</th><th>बहुवचनम्</th></tr><tr><td>**1. तृतीयः**</td><td>**-sam**</td><td>**-sma**</td><td>**-si**</td><td>**-smahi**</td></tr><tr><td>**2. द्वितीयः**</td><td>**-sīs**</td><td>**-sta**</td><td>**-sthās**</td><td>**-dhvam**</td></tr><tr><td>**3. प्रथमः**</td><td>**-sīt**</td><td>**-sur**</td><td>**-sta**</td><td>**-sata**</td></tr></tbody></table><p>Es wird das allgemeine Lautgesetz angewendet, dass ein Zischlaut zwischen zwei Verschlusslauten ausfällt (vgl. उद् + स्थित » उत्थित), d.h. das Stammbildungssuffix -s- vor Endungen, die mit -t- oder -th- beginnen, entfällt (nicht aber nach Nasalen oder r-).</p><p>Beispiele:</p><blockquote><p>3.sg.Ā a-kṣip + s + ta » अक्षिप्त<br> 2.sg.Ā a-kṣip + s + thās » अक्षिप्थास्</p></blockquote><p>Solche Formen könnten auch zum Wurzelaorist gehören und gehören vermutlich z.T. auch dorthin.</p><p>Die indischen Grammatiker haben auch Formen wie अकृत (3.sg.Ā) zum s-Aorist gerechnet, die eindeutig zum Wurzelaorist gehören. Zu diesem Zweck haben die indischen Grammatiker folgende ad-hoc Lautregel für den s-Aorist erfunden:</p><blockquote><p>&quot;Nach kurzem Vokal verlieren die &quot;Endungen&quot;, die mit -st- oder -sth- beginnen, das -s-.&quot;</p></blockquote><p>Sonst sind die Lautregeln für die Verbindung auslautender Konsonanten mit s- zu beachten.</p><p>Für -dhvam gilt:</p><p>Das -dh- von -dhvam wird nach allen Nicht-a/ā-Vokalen sowie nach -r durch -ḍh- ersetzt.</p><blockquote><p>z.B. चि 5U: 2.pl.Ā अचेढ्वम्</p></blockquote><p>Form der Wurzel:</p><ul><li>परस्मैपद : Dehnstufe</li><li>आत्मनेपद : <ul><li>Wurzeln mit auslautendem i/ī/u/ū: Hochstufe</li><li>auslautendes -ṝ wird durch -īr oder -ūr ersetzt</li><li>ablautfähige Wurzeln auf ā/e/o: Tiefstufe</li><li>andere Wurzelvokale: unverändert (d.h. in der Regel tiefstufig)</li></ul></li></ul><p>Beispiele:</p><blockquote><p>|   | 3.sg.P</p><p>| | --- | --- | | चि 5U |</p><p>अचैषीत्</p><p>| | श्रु 5P | अश्रौषीत् | | कृ 8U | अकार्षीत् | | भज् 1U | अभाक्षीत् | | भञ्ज् 7P | अभाङ्क्षीत् | | भुज् 7U | अभौक्षीत् |</p></blockquote><blockquote><p>|   | 3.sg.Ā</p><p>| | --- | --- | | चि 5U |</p><p>अचेष्ट</p><p>| | नी 1U | अनेष्ट | | सू 2/4 | असोष्ट | |   | sg.Ā | | दा 3U | अदिषि<br> अदिथास्<br> अदित | |   | 1.sg.Ā | | कृ 8U | अकृषि | | पच् 1U | अपक्षि |</p></blockquote><p>दृश् und सृज् haben im परस्मैपद Dehnstufe mit steigendem Diphton -rā-:</p><blockquote><p>दृश् 3.sg.P अद्राक्षीत्</p></blockquote><p>Auch der Aorist andere Wurzeln mit -ṛ- an vorletzter Stelle kann so gebildet werden:</p><blockquote><p>कृष् 1P/6U 3.sg.P अकार्क्षीत् / अक्राक्षीत्</p></blockquote><p>Paradigmen:</p><p>नी 1U &quot;führen&quot;</p><blockquote><table><tbody><tr><td></td><th colspan="2">परस्मैपदम्</th><th colspan="2">आत्मनेपदम्</th></tr><tr><td></td><th>एकवचनम्</th><th>बहुवचनम्</th><th>एकवचनम्</th><th>बहुवचनम्</th></tr><tr><td>**1. तृतीयः**</td><td>अनैषम्</td><td>अनैष्म</td><td>अनेषि</td><td>अनेष्महि</td></tr><tr><td>**2. द्वितीयः**</td><td>अनैषीस्</td><td>अनैष्ट</td><td>अनेष्ठास्</td><td>अनेढ्वम्</td></tr><tr><td>**3. प्रथमः**</td><td>अनैषीत्</td><td>अनैषुर्</td><td>नेष्ट</td><td>अनेषत</td></tr></tbody></table></blockquote><p><img src="'+r+'" alt=""><br> Abb.: भीमराव रामजी आंबेडकर (१८९१ - १९५६) । सो ऽनैषीद्दलितान् ॥<br> [Bildquelle: Wikipedia. Public Domain]</p><p>कृ 8U &quot;tun&quot;</p><blockquote><table><tbody><tr><td></td><th colspan="2">परस्मैपदम्</th><th colspan="2">आत्मनेपदम्</th></tr><tr><td></td><th>एकवचनम्</th><th>बहुवचनम्</th><th>एकवचनम्</th><th>बहुवचनम्</th></tr><tr><td>**1. तृतीयः**</td><td>अकार्षम्</td><td>अकार्ष्म</td><td>अकृषि</td><td>अकृष्महि</td></tr><tr><td>**2. द्वितीयः**</td><td>अकार्षीस्</td><td>अकार्ष्ट</td><td>अकृथास्</td><td>अकृढ्वम्</td></tr><tr><td>**3. प्रथमः**</td><td>अकार्षीत्</td><td>अकार्षुर्</td><td>अकृत</td><td>अकृषत</td></tr></tbody></table></blockquote><p>तुद् 6U &quot;schlagen&quot;</p><blockquote><table><tbody><tr><td></td><th colspan="2">परस्मैपदम्</th><th colspan="2">आत्मनेपदम्</th></tr><tr><td></td><th>एकवचनम्</th><th>बहुवचनम्</th><th>एकवचनम्</th><th>बहुवचनम्</th></tr><tr><td>**1. तृतीयः**</td><td>अतौत्सम्</td><td>अतौत्स्म</td><td>अतुत्सि</td><td>अतुत्स्महि</td></tr><tr><td>**2. द्वितीयः**</td><td>अतौत्सीस्</td><td>अतौत्त<br>aus: a-taut + s + ta</td><td>अतुत्थास्</td><td>अतुद्ध्वम्</td></tr><tr><td>**3. प्रथमः**</td><td>अतौत्सीत्</td><td>अतौत्सुर्</td><td>अतुत्त</td><td>अतुत्सत</td></tr></tbody></table></blockquote><p>Unregelmäßige Formen:</p><ol><li>Wurzeln auf Nasal (गम्, मन्, रम्) bilden den s-Aorist hochstufig:<br> अगंसि । अमंसि । अरंस्त<br> Daneben gibt es für गम् die regelmäßigen tiefstufigen Formen:<br> अगसि (« *a-gm-si) । अगथास् । अगत (im P hat गम् den themavokalischen Aorist)</li><li>पद् 4Ā ist regelmäßig (z.B. अपत्सि), in der 3.sg.Ā hat es aber die Form des passivischen Wurzelaorist:<br> अपादि &quot;er ging&quot;</li><li>बुध् Ā kann in der 3.sg.Ā wahlweise die Form des passiven Wurzelaorists annehmen:<br> अबोधि / अबुद्ध &quot;er erkannte&quot;</li></ol><h2 id="_57-2-ubung" tabindex="-1">57.2. Übung <a class="header-anchor" href="#_57-2-ubung" aria-label="Permalink to &quot;57.2. Übung&quot;">​</a></h2><p>A) Übersetzen und bestimmen Sie ohne Hilfsmittel folgende Formen und bilden Sie die entsprechenden Aoristformen. Außer bei Kausativen und Wurzeln, die den s-Aorist bilden, ist in Klammer die Klasse des entsprechenden Aorists angegeben:</p><ol><li>पेचिथ</li><li>अवक् (३)</li><li>सोष्यसि</li><li>छिन्दे</li><li>कुरुषे</li><li>आधत्ते</li><li>पद्यते</li><li>जिगाय</li><li>जिघ्रामः (१,६)</li><li>शासति (२)</li><li>स्तुवे</li><li>दिग्धे</li><li>प्लवध्वे</li><li>तस्थिथ (१)</li><li>बिभ्यति</li><li>ततर्प</li><li>जुहुथ</li><li>ऊषुः</li><li>ससर्जिथ</li><li>लिल्यिरे</li><li>अत्याजयम्</li><li>सिध्यथ (२)</li><li>निन्य</li><li>कर्षन्ति</li><li>अप्रच्छयन्</li></ol><p>B) Übersetzen und bestimmen Sie folgende Formen:</p><ol><li>चेलुः</li><li>जन्तुः</li><li>अश्वसीत्</li><li>ज्येष्ठायाः</li><li>संयक्</li><li>असे</li><li>असि</li><li>अचैष्ट</li><li>अचेष्ट</li><li>अभग्नम्</li><li>भस्म</li><li>हवींषि</li><li>अद्राक्षीः</li><li>शनैः</li><li>अपन्थाः</li><li>शत्रुह</li><li>उदासीने</li><li>कनीयान्</li><li>कन्याम्</li><li>आरम्</li><li>रिपू</li><li>अदात्</li><li>आदत्</li><li>अवोढ</li><li>अवोचम्</li><li>दिक्</li><li>शुनोः</li><li>यते</li><li>येते</li><li>याते</li><li>चतस्रः</li><li>परंपरायै</li><li>विमलाभ्याम्</li><li>ते</li><li>रजसि</li><li>रजसी</li><li>विक्रेढ्वम्</li><li>युष्मत्</li><li>अघम्</li><li>अभुक्थाः</li><li>उत्थानाय</li><li>अलुम्पत</li><li>अलुपत</li><li>अलुप्त</li><li>अलुप्तम्</li><li>वसिष्ठे</li><li>वर्षिष्ठे</li><li>अक्षैष्म</li><li>अहृत</li><li>कामधुग्भिः</li><li>अमुत्र</li><li>पत्युः</li><li>क्षेपीयन्</li><li>आदि्षि</li><li>पाणी</li><li>अस्प्राक्षम्</li></ol>',45)])])}const m=i(n,[["render",s]]);export{c as __pageData,m as default};
